//! # UCP CLI
//!
//! The command‑line interface for the Universal Component Protocol.
//!
//! Provides subcommands for bootstrapping, validation, merging, curation,
//! diff, token merging, drift detection, registry management, exporting,
//! and watch mode.

use anyhow::Context;
use clap::{Parser, Subcommand, ValueEnum};
use std::os::unix::process::CommandExt;
use std::path::{Path, PathBuf};
use ucp_core::cam::PackageManifest;
use ucp_maintainer::{
    diff::diff_specs_text,
    watch,
    registry::SpecStore,
    tokens::{merge_token_files, TokenMergeOptions},
    verify::verify_spec_against_source,
    mcp::run_mcp_server,
};
use ucp_synthesizer::merge::MergeOptions;
use ucp_synthesizer::pipeline::SynthesisOutput;

#[derive(ValueEnum, Clone, Debug)]
enum GeneratorTarget {
    Dioxus,
    Leptos,
    React,
    Gpui,
    #[clap(name = "web-components")]
    WebComponents,
    #[clap(name = "shadcn-registry")]
    ShadcnRegistry,
}

#[derive(ValueEnum, Clone, Debug)]
enum ExportTarget {
    A2ui,
    #[clap(name = "ag-ui")]
    AgUi,
    Dtcg,
    #[clap(name = "design-md")]
    DesignMd,
    #[clap(name = "llms-txt")]
    LlmsTxt,
}

#[derive(ValueEnum, Clone, Debug)]
enum ImportTarget {
    #[clap(name = "design-md")]
    DesignMd,
}

#[derive(Parser)]
#[command(name = "ucp", about = "UCP v4.0 AI Unification Engine", version)]
/// UCP CLI argument parser.
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    Bootstrap {
        #[arg(long)]
        source_dir: String,
        #[arg(long, default_value = "./ucp-output")]
        output_dir: String,
        #[arg(long)]
        ollama_url: Option<String>,
        #[arg(long, default_value = "glm-5:cloud")]
        llm_model: String,
        #[arg(long)]
        watch: bool,
    },
    Validate {
        spec: PathBuf,
    },
    Generate {
        #[arg(long)]
        spec: PathBuf,
        #[arg(long, short = 't')]
        target: GeneratorTarget,
        #[arg(long, short = 'o', default_value = "./generated")]
        output: PathBuf,
    },
    Dashboard {
        #[arg(long)]
        spec: PathBuf,
        #[arg(long, short = 'o', default_value = "./dashboard")]
        output: PathBuf,
    },
    Mcp {
        #[arg(long)]
        spec: PathBuf,
    },
    McpServerJson {
        #[arg(long, short = 'n', default_value = "ucp-server")]
        name: String,
        #[arg(long, short = 'd', default_value = "UCP Component Intelligence Server")]
        description: String,
        #[arg(long, short = 'o', default_value = "./mcp")]
        output: PathBuf,
    },
    Contract {
        #[arg(long)]
        spec: PathBuf,
        #[arg(long, short = 'o', default_value = "./ucp-contract.json")]
        output: PathBuf,
    },
    Import {
        #[arg(long, short = 't')]
        target: ImportTarget,
        #[arg(long)]
        spec: PathBuf,
        #[arg(long, short = 'o', default_value = "./ucp-output")]
        output: PathBuf,
    },
    Export {
        #[arg(long, short = 't')]
        target: ExportTarget,
        #[arg(long)]
        spec: PathBuf,
        #[arg(long, short = 'o', default_value = "./export")]
        output: PathBuf,
        #[arg(long, default_value = "ucp-library")]
        library: String,
        #[arg(long, default_value = "0.1.0")]
        version: String,
    },
    Registry {
        #[command(subcommand)]
        action: RegistryAction,
    },
    Merge {
        #[arg(long, num_args = 1..)]
        input: Vec<PathBuf>,
        #[arg(long, short = 'o', default_value = "./ucp-output/merged.json")]
        output: PathBuf,
        #[arg(long, default_value = "./ucp-output")]
        html_dir: String,
    },
    Components {
        spec: PathBuf,
        #[arg(long, default_value = "text", value_parser = ["text", "json"])]
        format: String,
        #[arg(long, short = 'f')]
        filter: Option<String>,
        #[arg(long, short = 'v')]
        verbose: bool,
    },
    /// v0.11: Interactive merge curation
    Curate {
        #[arg(long)]
        merged: PathBuf,
        #[arg(long, short = 'o', default_value = "./curated.json")]
        output: PathBuf,
    },
    /// v0.11: Structural spec diff
    Diff {
        #[arg(long)]
        spec_a: PathBuf,
        #[arg(long)]
        spec_b: PathBuf,
        #[arg(long)]
        json: bool,
    },
    /// v0.11: Merge DTCG tokens
    MergeTokens {
        #[arg(long, num_args = 1..)]
        input: Vec<PathBuf>,
        #[arg(long, short = 'o', default_value = "./merged-tokens.json")]
        output: PathBuf,
        #[arg(long, default_value = "error")]
        strategy: String,
        #[arg(long)]
        force: bool,
    },
    /// v0.11: Drift detection
    VerifySpec {
        #[arg(long)]
        spec: PathBuf,
        #[arg(long)]
        source_dir: PathBuf,
    },
    /// v0.11: Local spec registry management
    RegistryStore {
        #[arg(long)]
        db: Option<PathBuf>,
        #[command(subcommand)]
        action: RegistryStoreAction,
    },
    /// v0.11: Watch source directory and auto-rebuild
    Watch {
        #[arg(long)]
        source_dir: String,
        #[arg(long, short = 'o', default_value = "./watch-output")]
        output: PathBuf,
        #[arg(long)]
        base_spec: Option<PathBuf>,
        #[arg(long, default_value = "ucp-library")]
        library: String,
        #[arg(long, default_value = "0.1.0")]
        version: String,
        #[arg(long, default_value = "500")]
        debounce_ms: u64,
    },
    /// v0.11: Export all formats
    ExportAll {
        #[arg(long)]
        spec: PathBuf,
        #[arg(long, short = 'o', default_value = "./export-all")]
        output: PathBuf,
        #[arg(long, default_value = "ucp-library")]
        library: String,
        #[arg(long, default_value = "0.1.0")]
